#include <bits/stdc++.h>
using namespace std;
const int MOD=1000000007;
bool isPal(int mask,int K){
    int bits[20];
    for(int i=0;i<K;i++) bits[i]=(mask>>i)&1;
    for(int i=0;i<K/2;i++) if(bits[i]!=bits[K-1-i]) return false;
    return true;
}
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N,K;cin>>N>>K;
        if(K==1){
            cout<<0<<"\n";
            continue;
        }
        int stateBits=K-1;
        int maxMask=1<<stateBits;
        vector<int> dp(maxMask,0), ndp(maxMask,0);
        dp[0]=1;
        for(int pos=0;pos<N;pos++){
            fill(ndp.begin(), ndp.end(), 0);
            for(int mask=0; mask<maxMask; ++mask){
                int cur=dp[mask];
                if(!cur) continue;
                for(int b=0;b<2;b++){
                    int newMask=((mask<<1)|b)&((1<<K)-1);
                    bool ok=true;
                    if(pos+1>=K && isPal(newMask,K)) ok=false;
                    if(ok){
                        int nextMask=newMask & ((1<<stateBits)-1);
                        ndp[nextMask]=(ndp[nextMask]+cur)%MOD;
                    }
                }
            }
            dp.swap(ndp);
        }
        long long ans=0;
        for(int v:dp) ans=(ans+v)%MOD;
        cout<<ans<<"\n";
    }
    return 0;
}

